def find_kth_smallest_in_union(arr1, arr2, k):
    """
    Finds the kth smallest element in the union of two sorted arrays.

    Args:
        arr1: The first sorted array.
        arr2: The second sorted array.
        k: The desired rank of the element to find (1-indexed).

    Returns:
        The kth smallest element in the union of arr1 and arr2.
    """

    if not arr1:
        return arr2[k - 1]
    if not arr2:
        return arr1[k - 1]
    if k == 1:
        return min(arr1[0], arr2[0])

    i = min(len(arr1), k // 2)
    j = min(len(arr2), k // 2)

    if arr1[i - 1] < arr2[j - 1]:
        return find_kth_smallest_in_union(arr1[i:], arr2, k - i)
    else:
        return find_kth_smallest_in_union(arr1, arr2[j:], k - j)
